function getRecommendedApplications(sector, eventType) {
  return Object.values(aiApplications).filter((app) => app.sectors.includes(sector) && app.eventTypes.includes(eventType)).sort((a, b) => {
    const priorityOrder = { high: 0, medium: 1, low: 2 };
    return priorityOrder[a.priority] - priorityOrder[b.priority] || a.name.localeCompare(b.name);
  });
}
function getTopRecommendedApplications(sector, eventType, limit = 5) {
  return getRecommendedApplications(sector, eventType).slice(0, limit);
}
function getApplicationsByCategory(category) {
  return Object.values(aiApplications).filter((app) => app.category === category).sort((a, b) => a.name.localeCompare(b.name));
}
function getAllCategories() {
  const categories = new Set(Object.values(aiApplications).map((app) => app.category));
  return Array.from(categories).sort();
}
