      pushTranscriptSegment: operatorProcedure.input(z42.object({
        sessionId: z42.number(),
        speaker: z42.string().default("Speaker"),
        text: z42.string().min(1),
        timestamp: z42.number(),
        timeLabel: z42.string().optional()
      })).mutation(async ({ input }) => {
        const db2 = await getDb();
        const [session] = await db2.select().from(shadowSessions).where(eq55(shadowSessions.id, input.sessionId)).limit(1);
        if (!session) throw new Error("Session not found");
        if (session.status !== "live" && session.status !== "bot_joining") {
          throw new Error("Session is not active");
        }
        const segment = {
          speaker: input.speaker,
          text: input.text,
          timestamp: input.timestamp,
          timeLabel: input.timeLabel ?? new Date(input.timestamp).toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit" })
        };
        const existingTranscript = session.localTranscriptJson ? JSON.parse(session.localTranscriptJson) : [];
        existingTranscript.push(segment);
        await db2.update(shadowSessions).set({
          transcriptSegments: existingTranscript.length,
          localTranscriptJson: JSON.stringify(existingTranscript)
        }).where(eq55(shadowSessions.id, input.sessionId));
        if (session.ablyChannel) {
          const ABLY_API_KEY3 = process.env.ABLY_API_KEY ?? "";
          if (ABLY_API_KEY3) {
            const url = `https://rest.ably.io/channels/${encodeURIComponent(session.ablyChannel)}/messages`;
            const body = JSON.stringify({
              name: "curalive",
              data: JSON.stringify({ type: "transcript.segment", data: segment })
            });
            try {
              await fetch(url, {
                method: "POST",
                headers: {
                  Authorization: `Basic ${Buffer.from(ABLY_API_KEY3).toString("base64")}`,
                  "Content-Type": "application/json"
                },
                body
              });
            } catch (err) {
              console.warn("[Shadow] Ably publish for local segment failed:", err);
            }
          }
        }
        return { success: true, segmentCount: existingTranscript.length };
      }),
      deleteSession: operatorProcedure.input(z42.object({ sessionId: z42.number() })).mutation(async ({ input }) => {
        const db2 = await getDb();
        const [session] = await db2.select().from(shadowSessions).where(eq55(shadowSessions.id, input.sessionId)).limit(1);
        if (!session) throw new Error("Session not found");
        if (session.status === "live" || session.status === "bot_joining") {
          throw new Error("Cannot delete an active session. End it first.");
        }
        const eventId = `shadow-${session.id}`;
        await db2.delete(taggedMetrics).where(eq55(taggedMetrics.eventId, eventId));
        if (session.recallBotId) {
          try {
            await db2.delete(recallBots).where(eq55(recallBots.recallBotId, session.recallBotId));
          } catch {
          }
        }
        if (session.eventType === "agm") {
          try {
            await db2.delete(agmIntelligenceSessions).where(eq55(agmIntelligenceSessions.shadowSessionId, session.id));
          } catch {
          }
        }
        if (session.localRecordingPath) {
          try {
            const { unlinkSync: unlinkSync2 } = await import("fs");
            const { join: join4 } = await import("path");
            unlinkSync2(join4(process.cwd(), session.localRecordingPath));
          } catch {
          }
        }
        await db2.delete(shadowSessions).where(eq55(shadowSessions.id, input.sessionId));
        console.log(`[Shadow] Session ${input.sessionId} deleted`);
        return { success: true, message: "Session deleted" };
      }),
      deleteSessions: operatorProcedure.input(z42.object({ sessionIds: z42.array(z42.number()).min(1).max(100) })).mutation(async ({ input }) => {
        const db2 = await getDb();
        const sessions = await db2.select().from(shadowSessions).where(inArray(shadowSessions.id, input.sessionIds));
        const deletable = sessions.filter(
          (s) => s.status !== "live" && s.status !== "bot_joining"
        );
        if (deletable.length === 0) {
          throw new Error("No deletable sessions found (active sessions cannot be deleted).");
        }
        const ids = deletable.map((s) => s.id);
        const eventIds = ids.map((id) => `shadow-${id}`);
        await db2.delete(taggedMetrics).where(inArray(taggedMetrics.eventId, eventIds));
        const recallBotIds = deletable.map((s) => s.recallBotId).filter(Boolean);
        if (recallBotIds.length > 0) {
          try {
            await db2.delete(recallBots).where(inArray(recallBots.recallBotId, recallBotIds));
          } catch {
          }
        }
        const agmIds = deletable.filter((s) => s.eventType === "agm").map((s) => s.id);
        if (agmIds.length > 0) {
          try {
            await db2.delete(agmIntelligenceSessions).where(inArray(agmIntelligenceSessions.shadowSessionId, agmIds));
          } catch {
          }
        }
        for (const s of deletable) {
          if (s.localRecordingPath) {
            try {
              const { unlinkSync: unlinkSync2 } = await import("fs");
              const { join: join4 } = await import("path");
              unlinkSync2(join4(process.cwd(), s.localRecordingPath));
            } catch {
            }
          }
        }
        await db2.delete(shadowSessions).where(inArray(shadowSessions.id, ids));
        console.log(`[Shadow] Bulk deleted ${ids.length} sessions: ${ids.join(", ")}`);
        return { success: true, deleted: ids.length, message: `${ids.length} session${ids.length > 1 ? "s" : ""} deleted` };
      }),
