    { name: "Investor Engagement", score: cici.investorEngagement, benchmark: benchmark.engagement, weight: 0.25 },
    { name: "Compliance Quality", score: cici.complianceQuality, benchmark: benchmark.compliance, weight: 0.2 },
    { name: "Market Confidence", score: cici.marketConfidence, benchmark: benchmark.market, weight: 0.2 }
